# -*- coding: utf-8 -*-import jsonimport loggingimport osimport uuidimport pytzimport requestsfrom odoo import models, fields, _, apifrom odoo.exceptions import UserErrorfrom odoo.osv import expressiongrey = "\x1b[38;21m"yellow = "\x1b[33;21m"red = "\x1b[31;21m"bold_red = "\x1b[31;1m"reset = "\x1b[0m"green = "\x1b[32m"blue = "\x1b[34m"# Ahmed Salama Code Start ---->METHODS = [('GET-/api/v1.0/documenttypes', 'Get Document Types'),           ('GET-/api/v1.0/documents/recent', 'Get Recent Documents'),           ('POST-/api/v1/documentsubmissions', 'Submit Documents')]ENV = {'uat': '../data/EEI - UAT Env.postman_environment.json',  # 'UAT/PREPROD',       'sit': '../data/EEI - SIT Env.postman_environment.json',  # 'SIT',       'prod': '../data/EEI - PRD Env.postman_environment.json'}  # 'PRODUCTION'class ResCompanyInherit(models.Model):	_inherit = 'res.company'		activity_code_id = fields.Many2one('res.company.activity', "Activity Code", required=True)	type_code_id = fields.Many2one('account.tax.type.code', "Default Tax Type", required=True,	                               help="To be used in informing of Egyptian Taxes Foundation.")	sub_type_code_id = fields.Many2one('account.tax.sub.type.code', "Default Sub Tax Type", required=True,	                                   domain="[('type_id','=',type_code_id)]",	                                   help="To be used in informing of Egyptian Taxes Foundation.")	client_id = fields.Char("Client ID")	client_secret = fields.Char("Client Secret")	config_version = fields.Selection([('0.9', '0.9'), ('1.0', '1.0')], required=True,	                                  string='VERSION', default="0.9",	                                  help="- 0.9 for shipment without signature\n"	                                       "- 1.0 for dosuments with signature")	config_type = fields.Selection([('uat', 'UAT/PREPROD'),	                                # ('sit', 'SIT'),	                                ('prod', 'PRODUCTION')], required=True,	                               string='ENVIRONMENT', default="uat",	                               help="Test environment of the solution (SIT and UAT/PreProd environments) depends on"	                                    " internally issued certificates. Therefore to be able to properly use either the"	                                    " Invoicing Portal or get to APIs that solution is exposing,"	                                    " first you need to configure trust of Root Certificate of the test environment"	                                    " in your own test and development environments")	max_invoice_per_batch = fields.Integer("Max Document Per Batch", default=50, required=True,	                                       help="The max number of document to be sent on 1 batch")	max_invoice_per_time = fields.Integer("Max Document Per Time", default=200, required=True,	                                      help="The max number of document to be sent on 1 time")	method = fields.Selection(METHODS, "Method", default='GET-/api/v1.0/documenttypes')		token_method = fields.Selection([('local', 'Local'), ('remote', 'Remotely')], "Token Method",	                                default='remote')	generated_token = fields.Text("Token")	last_generated_token = fields.Datetime("Token Date")	signature_tool = fields.Selection([('python', 'Python'), ('c#', 'C#')],	                                  "Signature Tool", default='python', invisible=True)	# TODO: python Case of hosting http://localhost:5001/sign	signature_url = fields.Char("Signature URL(Method1)", default='http://0.0.0.0:5001/sign')	signature_pin = fields.Char("Signature PIN", default="52510779")	signature_label = fields.Char("Signature Label", default="Egypt Trust")	# TODO: C# Case of hosting http://localhost:PROJ_NAME/api/InvoiceHasher/Serialize	signature_serializer = fields.Char("Signature Serializer",	                                   default='http://localhost:signature/api/InvoiceHasher/Serialize')	signature_hash = fields.Char("Signature Harsh", default='http://localhost:signature/api/InvoiceHasher/Hash')	last_extract_doc = fields.Integer("Last Extract document", default=1)		def test_call_e_invoice_api(self):		"""		Used to check if the connection is valid and get data		:return: UserError with result		"""		message = ""		if not self.method:			raise UserError(_("Please select method first to test with"))		access_token, client_id, client_secret, apiBaseUrl = self.get_access_token()		headers = {'Content-Type': "application/json", 'cache-control': "no-cache",		           'Accept': "application/json", "Accept-Language": "ar", 'Authorization': "Bearer %s" % access_token}		api_detail = self.method.split('-')		url = apiBaseUrl + api_detail[1]		method = api_detail[0]		result_lines = []		if method == "GET":			details = False			try:				response = requests.request(method=method, url=url, headers=headers, verify=False)			except Exception as e:				message = "Could Connect to %s due to connection error:\n %s" % (url, e)				logging.info(red + message + reset)				raise UserError(message)		elif method == "POST":			with open(os.path.join(os.path.dirname(__file__), '../data/Schema2.json'), 'r', encoding='utf8') as Schema:				document_schema = json.load(Schema)				for inv in document_schema['documents']:					inv['dateTimeIssued'] = fields.Datetime.now().astimezone(pytz.utc).strftime("%Y-%m-%dT%H:%M:%SZ")					inv['internalID'] = str(uuid.uuid1().hex)[:6]				print("document_schema: ", document_schema)				details = json.dumps(document_schema, indent=4)				try:					response = requests.request(method=method, url=url, headers=headers, data=details, verify=False)				except Exception as e:					message = "Could Connect to %s due to connection error:\n %s" % (url, e)					logging.info(red + message + reset)					raise UserError(message)		result_json_details = "<h3>GET ACCESS<h3/><b>URL:</b> %s<br/><br/><b>METHOD:</b> %s<br/><b>HEADERS:</b> %s" % \		                      (url, method, headers)		result_json_details += "<b>Token Success for Client ID: </b> %s<br/><br/><b>Secret: %s</b>" % (			client_id, client_secret)				result_json_details += "<br/><h3>Action<h3/><b>URL:</b> %s<br/><br/><b>HEADERS:</b> %s <br/><br/>" \		                       "<b>CLIENT ID:</b> [%s]<br/><br/><b>CLIENT SECRET:</b> [%s]<br/><br/><b>json:</b> %s" \		                       % (url, headers, client_id, client_secret, details)		message += "Response Status :%s Reason: %s\n\n" % (response.status_code, response.reason)		if response.status_code == 404:			message = "Connecting Egyptian taxes API to submit document respond with error code: [%s]" % response.status_code			message += "\n\nError Desc.: %s" % response.reason			raise UserError(_(message))		elif response.status_code in (200, 202):			try:				result = response.json()			except:				raise UserError(_("2001: ETA Doesn't respond correctly!!!\n Please try again later"))			logging.info(green + "Response: %s" % response + reset)			logging.info(green + "Result: %s" % result + reset)			if result.get('acceptedDocuments'):				message += "<h4 style='color:green'>Success submit of %s Document <h4><br/>" % len(					result['acceptedDocuments'])				for accept_detail in result['acceptedDocuments']:					result_lines.append((0, 0, {'internalId': accept_detail.get('internalId'),					                            'uuid': accept_detail['uuid'], 'line_action': 'success'}))					logging.info(green + "\n Invoice %s Accepted with UUID: </b> %s <br/>" %					             (accept_detail['internalId'], accept_detail['uuid']) + reset)			if result.get('rejectedDocuments'):				message += "<h4 style='color:red'>Errors on submit of %s Document <h4><br/>" % len(					result['rejectedDocuments'])				for reject_details in result['rejectedDocuments']:					line_error_desc = ""					for error in reject_details['error']['details']:						line_error_desc += "<ul><li><b>Code:</b> %s</li>" % error["code"]						line_error_desc += "<li><b>Message:</b> %s</li>" % error["message"]						line_error_desc += "<li><b>Exact field:</b> %s</li></ul>" % error["propertyPath"]					result_lines.append((0, 0, {'internalId': reject_details.get('internalId'),					                            'description': line_error_desc,					                            'line_action': 'error'}))			else:				message += "<h4 style='color:green'>Success Extract %s Document <h4><br/>" % len(result['result'])				for line in result.get('result'):					res_details = "<ul>"					for key, value in line.items():						res_details += "<li><b>%s:</b> %s</li>" % (key, value)					res_details += "</ul>"					result_lines.append((0, 0, {'internalId': line.get('internalId'), 'description': res_details,					                            'line_action': 'success'}))		else:			try:				result = response.json()			except:				raise UserError(_("2002: ETA Doesn't respond correctly!!!\n Please try again later"))			message = "Connecting Egyptian taxes API to Test document respond with error code: [%s]" % response.status_code			message += "\n\nError Desc.: %s" % response.reason			message += "\n\nDetails: %s" % result						raise UserError(_(message))		# Return Results in view		res_id = self.env['electronic.invoice.result'].create(			{'results': message, 'name': dict(self._fields['method'].selection).get(self.method),			 'line_ids': result_lines,			 'json_details': result_json_details})		action = self.env.ref('egyptian_electronic_invoice.action_electronic_invoice_result').read()[0]		action['res_id'] = res_id.id		return action		def get_access_token(self):		with open(os.path.join(os.path.dirname(__file__), ENV[self.config_type]), 'r', encoding='utf8') as f:			distros_dict = json.load(f)		idSrvBaseUrl = distros_dict['values'][1]['value']		apiBaseUrl = distros_dict['values'][0]['value']		client_id = self.client_id		client_secret = self.client_secret		if not client_id and not client_secret:			client_id = distros_dict['values'][2]['value']			client_secret = distros_dict['values'][3]['value']		if self.env.context.get('manual'):			access_token = self._generate_token(idSrvBaseUrl, client_id, client_secret)		elif self.generated_token and self.last_generated_token and \				(fields.Datetime.now() - self.last_generated_token).seconds < 3600:			access_token = self.generated_token  # Get from static saved		else:			access_token = self._generate_token(idSrvBaseUrl, client_id, client_secret)		return access_token, client_id, client_secret, apiBaseUrl		def _generate_token(self, idSrvBaseUrl, client_id, client_secret):		headers = {'content-type': "application/x-www-form-urlencoded", 'cache-control': "no-cache"}		payload = {			'grant_type': 'client_credentials',			'client_id': client_id,			'client_secret': client_secret,			'scope': 'InvoicingAPI',		}		token_url = idSrvBaseUrl + "/connect/token"		try:			response = requests.post(token_url, headers=headers, data=payload, verify=False)		except Exception as e:			message = "Could Connect to %s due to connection error:\n %s" % (token_url, e)			logging.info(red + message + reset)			raise UserError(message)		result = False		if response.status_code != 404:			try:				result = response.json()			except:				raise UserError(_("2003: ETA Doesn't respond correctly!!!\n Please try again later"))		if response.status_code in (200, 202):			logging.info(green + "Token Respond: %s" % result + reset)			access_token = result['access_token']			self.generated_token = access_token			self.last_generated_token = fields.Datetime.now()			return access_token		else:			try:				result = response.json()			except:				raise UserError(_("2004: ETA Doesn't respond correctly!!!\n Please try again later"))			message = "Connecting Egyptian taxes API to get Access token respond with error code:%s" % response.status_code			message += "\n\nError Desc.: %s %s" % (response.reason, result and result['error'] or "")			if self.env.user.has_group('egyptian_electronic_invoice.group_e_invoice_dev_tools'):				message += " \n URL:%s \n\n HEADERS:%s" % \				           (token_url, headers,)			raise UserError(_(message))		def get_recent_documents(self):		access_token, client_id, client_secret, apiBaseUrl = self.get_access_token()		show_result = self.env.context.get('show_result')		headers = {'Content-Type': "application/json", 'cache-control': "no-cache",		           'Accept': "application/json", "Accept-Language": "ar", 'Authorization': "Bearer %s" % access_token}		page_num = 1		page_size = 1000000		# if self.last_extract_doc != 1:		# 	page_num = 2		# 	page_size = self.last_extract_doc		url = apiBaseUrl + '/api/v1.0/documents/recent?pageNo=%s&pageSize=%s' % (page_num, page_size)		result_lines = []		try:			response = requests.request(method='get', url=url, headers=headers, verify=False)		except Exception as e:			message = "Could Connect to %s due to connection error:\n %s" % (url, e)			logging.info(red + message + reset)			raise UserError(message)		if show_result:			message = "Response Status :%s Reason: %s\n\n" % (response.status_code, response.reason)		if response.status_code == 404:			if show_result:				message = "Connecting Egyptian taxes API to submit document respond with error code: [%s]" % response.status_code				message += "\n\nError Desc.: %s" % response.reason				raise UserError(_(message))		elif response.status_code in (200, 202):			try:				result = response.json()			except:				raise UserError(_("2001: ETA Doesn't respond correctly!!!\n Please try again later"))			logging.info(green + "Response: %s" % response + reset)			logging.info(green + "Result: %s" % result + reset)			lines = result.get('result')			if result.get('metadata') and result['metadata'].get('totalCount'):				self.last_extract_doc = result['metadata'].get('totalCount')						received_docs = []			for line in lines:				if line.get('receiverId') and line.get('receiverId') == self.env.company.vat:					received_docs.append(line)					if show_result:						res_details = "<ul>"						for key, value in line.items():							res_details += "<li><b>%s:</b> %s</li>" % (key, value)						res_details += "</ul>"						result_lines.append((0, 0, {'internalId': line.get('internalId'), 'description': res_details,						                            'line_action': 'success'}))			if show_result:				message += "<h4 style='color:green'>Success Get %s/%s Vendor Received Documents <h4><br/>" \				           % (len(received_docs), len(lines))			if received_docs:				self.generate_vendor_docs(received_docs)		else:			try:				result = response.json()			except:				raise UserError(_("2002: ETA Doesn't respond correctly!!!\n Please try again later"))			if show_result:				message = "Connecting Egyptian taxes API to Test document respond with error code: [%s]" % response.status_code				message += "\n\nError Desc.: %s" % response.reason				message += "\n\nDetails: %s" % result				raise UserError(_(message))		# Return Results in view		if show_result:			res_id = self.env['electronic.invoice.result'].create(				{'results': message, 'name': dict(self._fields['method'].selection).get(self.method),				 'line_ids': result_lines})			action = self.env.ref('egyptian_electronic_invoice.action_electronic_invoice_result').read()[0]			action['res_id'] = res_id.id			return action		def generate_vendor_docs(self, received_docs):		vendor_rec_docs_obj = self.env['vendor.received.document']		exist_docs = vendor_rec_docs_obj.search([])		for doc in received_docs:			doc_status = doc.get('validationResults') and doc['validationResults']['status'] or doc.get('status')			if doc.get('uuid') in exist_docs.mapped('name'):				exist_doc_id = exist_docs.filtered(lambda d: d.name == doc.get('uuid'))				if doc_status != exist_doc_id.document_status:					exist_doc_id.write({'document_status': doc_status})			else:				# Use received/issued date				date_time_issued = doc.get('dateTimeIssued').replace('T', ' ')				date_time_issued = '.' in date_time_issued and date_time_issued.split('.')[0] or date_time_issued				date_time_issued = date_time_issued.replace('Z', '')				date_time_received = doc.get('dateTimeReceived').replace('T', ' ')				date_time_received = '.' in date_time_received and date_time_received.split('.')[					0] or date_time_received				date_time_received = date_time_received.replace('Z', '')				# Fill Vals				vals = {					'name': doc.get('uuid'),					'submission_id': doc.get('submissionUUID'),					'document_type': doc.get('typeName').upper(),					'document_version': doc.get('typeVersionName'),					'issuer_id': doc.get('issuerId'),					'issuer_name': doc.get('issuerName'),					'receiver_id': doc.get('receiverId'),					'receiver_name': doc.get('receiverName'),					'document_status': doc_status,					'date_issued': date_time_issued,					'date_received': date_time_received,					'total_sales': doc.get('totalSales'),					'total_discount': doc.get('totalDiscount'),					'net_amount': doc.get('netAmount'),					'total': doc.get('total'),					'currency_id': self.env.company.currency_id.id,					'json': doc,					'line_ids': doc.get('invoiceLineItemCodes') and [(0, 0, {						'hs_type': line.get('codeTypeNamePrimaryLang'),						'hs_code': line.get('itemCode'),						'name': line.get('codeNamePrimaryLang'),						'hs_description': line.get('codeNameSecondaryLang'),					}) for line in doc.get('invoiceLineItemCodes')] or False				}				vendor_rec_docs_obj.create(vals)class CompanyActivityCode(models.Model):	_name = 'res.company.activity'	_description = "Company Activity Code"		name = fields.Char('Name')	ar_name = fields.Char('Arabic Name', required=True)	code = fields.Char("Code", required=True)	# Constrain in Code	_sql_constraints = [		('unique_activity_code', 'unique(code)', 'The Activity must be unique!'),	]		@api.depends('name', 'ar_name')	def name_get(self):		"""		Display name related to active user lang		"""		result = []		for activity in self:			name = activity.name			if 'ar' in self.env.user.lang:				name = activity.ar_name			result.append((activity.id, name))		return result		@api.model	def _name_search(self, name, args=None, operator='ilike', limit=100, name_get_uid=None):		"""		Add Search with Name/Ar Name/ Code		:param name:		:param args:		:param operator:		:param limit:		:param name_get_uid:		:return:		"""		args = args or []		domain = []		if name:			domain = ['|', '|', ('name', operator, name), ('ar_name', operator, name), ('code', operator, name)]		return self._search(expression.AND([domain, args]), limit=limit, access_rights_uid=name_get_uid)		@api.model	def load_activity_codes(self):		"""		Load All company Activity from JSON file		:return:		"""		activity_obj = self.env['res.company.activity']		with open(os.path.join(os.path.dirname(__file__), '../data/ActivityCodes.json'), 'r',		          encoding='utf8') as ActivityCodes:			activities = eval(json.dumps(json.load(ActivityCodes), indent=4))		if activities:			current_activities = activity_obj.search([]).mapped('code')			for activity in activities:				if activity.get('code') and activity.get('code') not in current_activities:					activity_obj.create({						'name': activity.get('Desc_en'),						'ar_name': activity.get('Desc_ar'),						'code': activity.get('code'),					})					logging.info(green + "Create New Activity: %s" % activity.get('code') + reset)# Ahmed Salama Code End.